import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Alert,
  CircularProgress,
  Paper,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupUser } from "../services/api";

export default function UserRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setFormData((p) => ({ ...p, [e.target.name]: e.target.value }));

  const validateEmail = (email) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateForm = () => {
    if (!formData.fullName || formData.fullName.length < 2) return setError("Enter a valid name.");
    if (!validateEmail(formData.email)) return setError("Enter a valid email.");
    if (!/^[6-9]\d{9}$/.test(formData.mobile)) return setError("Enter a valid mobile.");
    setError("");
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;
    setLoading(true);
    try {
      const res = await signupUser({ ...formData, role: "user" });
      if (res.data?.success) {
        setSuccess("Signup successful!");
        setTimeout(() => navigate("/login"), 800);
      } else setError(res.data?.message || "Signup failed");
    } catch {
      setError("Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 3, borderRadius: 3, textAlign: "center" }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
          User Signup
        </Typography>
        {error && <Alert severity="error">{error}</Alert>}
        {success && <Alert severity="success">{success}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" value={formData.fullName} onChange={handleChange} margin="normal" />
          <TextField fullWidth type="email" label="Email" name="email" value={formData.email} onChange={handleChange} margin="normal" />
          <TextField fullWidth type="tel" label="Mobile" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" />

          <Button type="submit" fullWidth sx={{ mt: 2 }} disabled={loading}>
            {loading ? <CircularProgress size={24} /> : "Sign Up"}
          </Button>
        </Box>

        <Typography sx={{ mt: 2 }}>
          Already have an account? <Button onClick={() => navigate("/login")}>Login</Button>
        </Typography>
        <Typography sx={{ mt: 1 }}>
          Want to drive with us? <Button onClick={() => navigate("/rider-register")}>Rider Signup</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
